#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        uint32_t a[N];
        for (int i = 0; i < N; i++) {
            scanf("%u", &a[i]);
        }
        uint32_t xor_sum = 0;
        for (int i = 0; i < N; i++) {
            xor_sum ^= a[i];
        }
        int64_t ways = 1;
        for (int i = 0; i < N; i++) {
            int count = 0;
            for (uint32_t j = 0; j <= a[i]; j++) {
                if ((j ^ a[i]) <= a[i]) {
                    count++;
                }
            }
            ways = (ways * count) % MOD;
        }
        printf("%lld\n", ways);
    }
    return 0;
}

