import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] a = new int[N];
            for (int i = 0; i < N; i++) {
                a[i] = sc.nextInt();
            }
            int xor_sum = 0;
            for (int i = 0; i < N; i++) {
                xor_sum ^= a[i];
            }
            long ways = 1;
            for (int i = 0; i < N; i++) {
                int count = 0;
                for (int j = 0; j <= a[i]; j++) {
                    if ((j ^ a[i]) <= a[i]) {
                        count++;
                    }
                }
                ways = (ways * count) % 1000000007;
            }
            System.out.println(ways);
        }
    }
}

